  1602 | 
  1603 |   LLVM_DEBUG(dbgs() << "Adding '"; dumpUnpackedICmp(dbgs(), Pred, A, B);
  1604 |              dbgs() << "'\n");
  1605 |   bool Added = false;
  1606 |   auto &CSToUse = getCS(R.IsSigned);
  1607 |   if (R.Coefficients.empty())
  1608 |     return;
  1609 | 
  1610 |   Added |= CSToUse.addVariableRowFill(R.Coefficients);
