  1612 |   // If R has been added to the system, add the new variables and queue it for
  1613 |   // removal once it goes out-of-scope.
  1614 |   if (Added) {
  1615 |     SmallVector<Value *, 2> ValuesToRelease;
  1616 |     auto &Value2Index = getValue2Index(R.IsSigned);
  1617 |     for (Value *V : NewVariables) {
