  1654 | static bool replaceSubOverflowUses(IntrinsicInst *II, Value *A, Value *B,
  1655 |                                    SmallVectorImpl<Instruction *> &ToRemove) {
  1656 |   bool Changed = false;
  1657 |   IRBuilder<> Builder(II->getParent(), II->getIterator());
  1658 |   Value *Sub = nullptr;
  1659 |   for (User *U : make_early_inc_range(II->users())) {
  1660 |     if (match(U, m_ExtractValue<0>(m_Value()))) {
  1661 |       if (!Sub)
  1662 |         Sub = Builder.CreateSub(A, B);
  1663 |       U->replaceAllUsesWith(Sub);
  1664 |       Changed = true;
  1665 |     } else if (match(U, m_ExtractValue<1>(m_Value()))) {
  1666 |       U->replaceAllUsesWith(Builder.getFalse());
  1667 |       Changed = true;
