  1252 | /// Helper function to generate a reproducer function for simplifying \p Cond.
  1253 | /// The reproducer function contains a series of @llvm.assume calls, one for
  1254 | /// each condition in \p Stack. For each condition, the operand instruction are
  1255 | /// cloned until we reach operands that have an entry in \p Value2Index. Those
  1256 | /// will then be added as function arguments. \p DT is used to order cloned
  1257 | /// instructions. The reproducer function will get added to \p M, if it is
  1258 | /// non-null. Otherwise no reproducer function is generated.
  1259 | static void generateReproducer(CmpInst *Cond, Module *M,
  1260 |                                ArrayRef<ReproducerEntry> Stack,
  1261 |                                ConstraintInfo &Info, DominatorTree &DT) {
  1262 |   if (!M)
  1263 |     return;
  1264 | 
  1265 |   LLVMContext &Ctx = Cond->getContext();
