  1267 |   LLVM_DEBUG(dbgs() << "Creating reproducer for " << *Cond << "\n");
  1268 | 
  1269 |   ValueToValueMapTy Old2New;
  1270 |   SmallVector<Value *> Args;
  1271 |   SmallPtrSet<Value *, 8> Seen;
  1272 |   // Traverse Cond and its operands recursively until we reach a value that's in
  1273 |   // Value2Index or not an instruction, or not a operation that
  1274 |   // ConstraintElimination can decompose. Such values will be considered as
  1275 |   // external inputs to the reproducer, they are collected and added as function
  1276 |   // arguments later.
  1277 |   auto CollectArguments = [&](ArrayRef<Value *> Ops, bool IsSigned) {
  1278 |     auto &Value2Index = Info.getValue2Index(IsSigned);
  1279 |     SmallVector<Value *, 4> WorkList(Ops);
  1280 |     while (!WorkList.empty()) {
  1281 |       Value *V = WorkList.pop_back_val();
  1282 |       if (!Seen.insert(V).second)
  1283 |         continue;
  1284 |       if (Old2New.find(V) != Old2New.end())
  1285 |         continue;
  1286 |       if (isa<Constant>(V))
  1287 |         continue;
  1288 | 
  1289 |       auto *I = dyn_cast<Instruction>(V);
  1290 |       if (Value2Index.contains(V) || !I ||
  1291 |           !isa<CmpInst, BinaryOperator, GEPOperator, CastInst>(V)) {
  1292 |         Old2New[V] = V;
  1293 |         Args.push_back(V);
  1294 |         LLVM_DEBUG(dbgs() << "  found external input " << *V << "\n");
  1295 |       } else {
  1296 |         append_range(WorkList, I->operands());
