   687 |       Pred != CmpInst::ICMP_SLE && Pred != CmpInst::ICMP_SLT)
   688 |     return {};
   689 | 
   690 |   SmallVector<ConditionTy, 4> Preconditions;
   691 |   bool IsSigned = CmpInst::isSigned(Pred);
   692 |   auto &Value2Index = getValue2Index(IsSigned);
   693 |   auto ADec = decompose(Op0->stripPointerCastsSameRepresentation(),
   694 |                         Preconditions, IsSigned, DL);
   695 |   auto BDec = decompose(Op1->stripPointerCastsSameRepresentation(),
   696 |                         Preconditions, IsSigned, DL);
