    if (isKnownNonNegative(Arg, DL)) {
      unsigned Idx = SignedValue2Index[Arg];
      ConstraintTy VarPos(SmallVector<int64_t, 8>(SignedValue2Index.size() + 1, 0),
                          true, false, false);
      VarPos.Coefficients[Idx] = -1;
